#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_NODES 2001
#define MAX_TRIPLES 4000001

// Structure to represent a triple
typedef struct {
    int x, y, z;
} Triple;

// Structure to represent a graph
typedef struct {
    int numNodes;
    int numTriples;
    Triple* triples;
} Graph;

// Function to create a graph
Graph* createGraph(int numTriples) {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->numTriples = numTriples;
    graph->triples = (Triple*)malloc(numTriples * sizeof(Triple));
    return graph;
}

// Function to add a triple to the graph
void addTriple(Graph* graph, int x, int y, int z) {
    Triple* triple = &graph->triples[graph->numNodes++];
    triple->x = x;
    triple->y = y;
    triple->z = z;
}

// Function to find the shortest path using BFS
int bfs(Graph* graph, int start, int end) {
    int* distances = (int*)malloc(MAX_NODES * sizeof(int));
    for (int i = 0; i < MAX_NODES; i++) {
        distances[i] = INT_MAX;
    }
    distances[start] = 0;

    int* queue = (int*)malloc(MAX_NODES * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = start;

    while (front < rear) {
        int node = queue[front++];
        for (int i = 0; i < graph->numTriples; i++) {
            if (graph->triples[i].x == node) {
                int neighbor = graph->triples[i].y;
                int weight = graph->triples[i].z;
                if (distances[neighbor] > distances[node] + weight) {
                    distances[neighbor] = distances[node] + weight;
                    queue[rear++] = neighbor;
                }
            } else if (graph->triples[i].y == node) {
                int neighbor = graph->triples[i].x;
                int weight = graph->triples[i].z;
                if (distances[neighbor] > distances[node] + weight) {
                    distances[neighbor] = distances[node] + weight;
                    queue[rear++] = neighbor;
                }
            }
        }
    }

    int result = distances[end];
    free(distances);
    free(queue);
    return result;
}

int main() {
    int numTriples, start, end;
    scanf("%d %d %d", &numTriples, &start, &end);

    Graph* graph = createGraph(numTriples);
    for (int i = 0; i < numTriples; i++) {
        int x, y, z;
        scanf("%d %d %d", &x, &y, &z);
        addTriple(graph, x, y, z);
    }

    int result = bfs(graph, start, end);
    if (result == INT_MAX) {
        printf("NO\n");
    } else {
        printf("YES\n%d\n", result);
    }

    free(graph->triples);
    free(graph);
    return 0;
}

