import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MAX_NODES = 2001;
    static final int MAX_TRIPLES = 4000001;

    // Structure to represent a triple
    static class Triple {
        int x, y, z;
    }

    // Structure to represent a graph
    static class Graph {
        int numNodes;
        int numTriples;
        Triple[] triples;
    }

    // Function to create a graph
    static Graph createGraph(int numTriples) {
        Graph graph = new Graph();
        graph.numTriples = numTriples;
        graph.triples = new Triple[numTriples];
        return graph;
    }

    // Function to add a triple to the graph
    static void addTriple(Graph graph, int x, int y, int z) {
        Triple triple = new Triple();
        triple.x = x;
        triple.y = y;
        triple.z = z;
        graph.triples[graph.numNodes++] = triple;
    }

    // Function to find the shortest path using BFS
    static int bfs(Graph graph, int start, int end) {
        int[] distances = new int[MAX_NODES];
        for (int i = 0; i < MAX_NODES; i++) {
            distances[i] = Integer.MAX_VALUE;
        }
        distances[start] = 0;

        Queue<Integer> q = new LinkedList<>();
        q.add(start);

        while (!q.isEmpty()) {
            int node = q.poll();
            for (int i = 0; i < graph.numTriples; i++) {
                if (graph.triples[i].x == node) {
                    int neighbor = graph.triples[i].y;
                    int weight = graph.triples[i].z;
                    if (distances[neighbor] > distances[node] + weight) {
                        distances[neighbor] = distances[node] + weight;
                        q.add(neighbor);
                    }
                } else if (graph.triples[i].y == node) {
                    int neighbor = graph.triples[i].x;
                    int weight = graph.triples[i].z;
                    if (distances[neighbor] > distances[node] + weight) {
                        distances[neighbor] = distances[node] + weight;
                        q.add(neighbor);
                    }
                }
            }
        }

        int result = distances[end];
        return result;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int numTriples = sc.nextInt();
        int start = sc.nextInt();
        int end = sc.nextInt();

        Graph graph = createGraph(numTriples);
        for (int i = 0; i < numTriples; i++) {
            int x = sc.nextInt();
            int y = sc.nextInt();
            int z = sc.nextInt();
            addTriple(graph, x, y, z);
        }

        int result = bfs(graph, start, end);
        if (result == Integer.MAX_VALUE) {
            System.out.println("NO");
        } else {
            System.out.println("YES");
            System.out.println(result);
        }
    }
}

